//! Structures and functions for user space.

use core::arch::naked_asm;
use memory_addr::VirtAddr;
use riscv::register::sstatus::Sstatus;
#[cfg(feature = "fp-simd")]
use riscv::register::sstatus::FS;

use crate::{GeneralRegisters, TrapFrame};

/// Context to enter user space.
pub struct UspaceContext(TrapFrame);

impl UspaceContext {
    /// Creates an empty context with all registers set to zero.
    pub const fn empty() -> Self {
        unsafe { core::mem::MaybeUninit::zeroed().assume_init() }
    }

    /// Creates a new context with the given entry point, user stack pointer,
    /// and the argument.
    pub fn new(entry: usize, ustack_top: VirtAddr, arg0: usize) -> Self {
        let mut sstatus = Sstatus::from_bits(0);
        sstatus.set_spie(true); // enable interrupts
        sstatus.set_sum(true); // enable user memory access in supervisor mode
        #[cfg(feature = "fp-simd")]
        {
            sstatus.set_fs(FS::Initial); // set the FPU to initial state
        }

        Self(TrapFrame {
            regs: GeneralRegisters {
                a0: arg0,
                sp: ustack_top.as_usize(),
                ..Default::default()
            },
            sepc: entry,
            sstatus,
        })
    }

    /// Creates a new context from the given [`TrapFrame`].
    pub const fn from(trap_frame: &TrapFrame) -> Self {
        Self(*trap_frame)
    }

    /// Gets the instruction pointer.
    pub const fn get_ip(&self) -> usize {
        self.0.sepc
    }

    /// Gets the stack pointer.
    pub const fn get_sp(&self) -> usize {
        self.0.regs.sp
    }

    /// Sets the instruction pointer.
    pub const fn set_ip(&mut self, pc: usize) {
        self.0.sepc = pc;
    }

    /// Sets the stack pointer.
    pub const fn set_sp(&mut self, sp: usize) {
        self.0.regs.sp = sp;
    }

    /// Sets the return value register.
    pub const fn set_retval(&mut self, a0: usize) {
        self.0.regs.a0 = a0;
    }

    /// Enters user space.
    ///
    /// It restores the user registers and jumps to the user entry point
    /// (saved in `sepc`).
    /// When an exception or syscall occurs, the kernel stack pointer is
    /// switched to `kstack_top`.
    ///
    /// # Safety
    ///
    /// This function is unsafe because it changes processor mode and the stack.
    pub unsafe fn enter_uspace(&self, kstack_top: VirtAddr) -> ! {
        crate::asm::disable_irqs();
        unsafe { enter_uspace_raw(core::ptr::addr_of!(self.0), kstack_top.as_usize()) }
    }
}

#[unsafe(naked)]
unsafe extern "C" fn enter_uspace_raw(_tf: *const TrapFrame, _kstack_top: usize) -> ! {
    naked_asm!(
        include_asm_macros!(),
        "
        csrw    sscratch, a1
        addi    a1, a1, -{trapframe_size}
        LDR     t0, a0, 32
        csrw    sepc, t0

        STR     gp, a1, 3
        LDR     gp, a0, 3

        STR     tp, a1, 4
        LDR     tp, a0, 4

        LDR     t0, a0, 33
        csrw    sstatus, t0
        mv      sp, a0
        POP_GENERAL_REGS
        LDR     sp, sp, 2
        sret
        ",
        trapframe_size = const core::mem::size_of::<TrapFrame>(),
    )
}

use core::fmt;

use alloc::collections::BTreeMap;
use alloc::vec::Vec;

use axerrno::{AxError, AxResult, ax_err};
use axhal::mem::phys_to_virt;
use axhal::paging::{MappingFlags, PageSize, PageTable};
use axhal::trap::PageFaultFlags;
use memory_addr::{
    MemoryAddr, PAGE_SIZE_4K, PageIter4K, PhysAddr, VirtAddr, VirtAddrRange, is_aligned_4k,
};
use memory_set::{MemoryArea, MemorySet};

use crate::backend::{Backend, retain_shared_frame};
use crate::mapping_err_to_ax_err;

/// The virtual memory address space.
pub struct AddrSpace {
    va_range: VirtAddrRange,
    areas: MemorySet<Backend>,
    pt: PageTable,
}

/// Diagnostic information for a single virtual address lookup.
#[derive(Clone, Copy, Debug)]
pub struct AddrSpaceQuery {
    pub contains: bool,
    pub area_found: bool,
    pub area_start: usize,
    pub area_end: usize,
    pub area_flags: MappingFlags,
    pub backend: &'static str,
    pub pte_mapped: bool,
    pub paddr: usize,
    pub pte_flags: MappingFlags,
    pub page_size: Option<PageSize>,
    pub shared_metadata: bool,
}

impl AddrSpace {
    /// Returns the address space base.
    pub const fn base(&self) -> VirtAddr {
        self.va_range.start
    }

    /// Returns the address space end.
    pub const fn end(&self) -> VirtAddr {
        self.va_range.end
    }

    /// Returns the address space size.
    pub fn size(&self) -> usize {
        self.va_range.size()
    }

    /// Returns the reference to the inner page table.
    pub const fn page_table(&self) -> &PageTable {
        &self.pt
    }

    /// Returns the root physical address of the inner page table.
    pub const fn page_table_root(&self) -> PhysAddr {
        self.pt.root_paddr()
    }

    /// Checks if the address space contains the given address range.
    pub fn contains_range(&self, start: VirtAddr, size: usize) -> bool {
        if start.as_usize().checked_add(size).is_none() {
            return false;
        }
        self.va_range
            .contains_range(VirtAddrRange::from_start_size(start, size))
    }

    /// Creates a new empty address space.
    pub(crate) fn new_empty(base: VirtAddr, size: usize) -> AxResult<Self> {
        Ok(Self {
            va_range: VirtAddrRange::from_start_size(base, size),
            areas: MemorySet::new(),
            pt: PageTable::try_new().map_err(|_| AxError::NoMemory)?,
        })
    }

    /// Copies page table mappings from another address space.
    ///
    /// It copies the page table entries only rather than the memory regions,
    /// usually used to copy a portion of the kernel space mapping to the
    /// user space.
    ///
    /// Returns an error if the two address spaces overlap.
    pub fn copy_mappings_from(&mut self, other: &AddrSpace) -> AxResult {
        if self.va_range.overlaps(other.va_range) {
            return ax_err!(InvalidInput, "address space overlap");
        }
        self.pt
            .cursor()
            .copy_from(&other.pt, other.base(), other.size());
        Ok(())
    }

    /// Clones all user mappings from another address space.
    ///
    /// Unlike [`Self::copy_mappings_from`], this duplicates user mappings even
    /// when the two address spaces cover the same virtual range. Allocation
    /// backends are recreated in the destination. Resident pages are retained
    /// as lazy shared metadata; writable pages are write-protected in both
    /// parent and child so copy-on-write can preserve isolation without
    /// eagerly duplicating the process's writable working set.
    pub fn clone_user_mappings_from(&mut self, other: &mut AddrSpace) -> AxResult {
        self.clone_user_mappings_from_inner(other, true)
    }

    /// Shares all current user mappings from another address space.
    ///
    /// This is intended for vfork-like process creation: the child owns a
    /// separate page table so exec/exit can tear it down independently, but
    /// resident writable pages are mapped to the same physical frames so child
    /// stores before exec/exit remain visible to the blocked parent.
    pub fn share_user_mappings_from(&mut self, other: &mut AddrSpace) -> AxResult {
        self.clone_user_mappings_from_inner(other, false)
    }

    fn clone_user_mappings_from_inner(
        &mut self,
        other: &mut AddrSpace,
        cow_writable: bool,
    ) -> AxResult {
        if self.va_range != other.va_range {
            return ax_err!(InvalidInput, "address space range mismatch");
        }

        self.clear();

        let mut parent_tlb_flush_needed = false;
        for area in other.areas.iter() {
            let mut shared_pages = BTreeMap::new();
            let mut retained_frames = Vec::new();
            let mut parent_protect_pages = Vec::new();
            let alloc_missing = area.backend().alloc_missing_on_fault();
            let cow_pages =
                cow_writable && area.flags().contains(MappingFlags::WRITE) && alloc_missing;
            for vaddr in PageIter4K::new(area.start(), area.end())
                .expect("memory area bounds must be 4K aligned")
            {
                let parent_pte = other.pt.query(vaddr).ok();
                let query = parent_pte.or_else(|| {
                    area.backend()
                        .shared_page(vaddr)
                        .map(|(paddr, flags)| (paddr, flags, PageSize::Size4K))
                });
