fn overlapping_mmap_regions<'a>(
    ranges: &'a [super::UserMmapRegion],
    start: usize,
    end: usize,
) -> impl Iterator<Item = &'a super::UserMmapRegion> + 'a {
    let first = first_overlapping_mmap_region(ranges, start);
    ranges[first..]
        .iter()
        .take_while(move |region| region.start < end)
}

