fn handle_breakpoint(era: &mut usize) {
    debug!("Exception(Breakpoint) @ {era:#x} ");
    *era += 4;
}

fn handle_page_fault(tf: &TrapFrame, mut access_flags: PageFaultFlags, is_user: bool) {
    if is_user {
        access_flags |= PageFaultFlags::USER;
    }
    let vaddr = va!(badv::read().raw());
    if !handle_trap!(PAGE_FAULT, vaddr, access_flags, is_user) {
        panic!(
            "Unhandled {} Page Fault @ {:#x}, fault_vaddr={:#x} ({:?}):\n{:#x?}",
            if is_user { "PLV3" } else { "PLV0" },
            tf.era,
            vaddr,
            access_flags,
            tf,
        );
    }
}

#[cfg(feature = "uspace")]
fn handle_user_signal(tf: &TrapFrame, signal: usize) -> bool {
    crate::trap::handle_user_exception(tf, signal)
}

#[unsafe(no_mangle)]
fn loongarch64_trap_handler(tf: &mut TrapFrame, from_user: bool) {
    let estat = estat::read();

    match estat.cause() {
        #[cfg(feature = "uspace")]
        Trap::Exception(Exception::Syscall) => {
            tf.regs.a0 = crate::trap::handle_syscall(tf, tf.regs.a7) as usize;
            tf.era += 4;
        }
        Trap::Exception(Exception::LoadPageFault)
        | Trap::Exception(Exception::PageNonReadableFault) => {
            handle_page_fault(tf, PageFaultFlags::READ, from_user)
        }
        Trap::Exception(Exception::StorePageFault)
        | Trap::Exception(Exception::PageModifyFault) => {
            handle_page_fault(tf, PageFaultFlags::WRITE, from_user)
        }
        Trap::Exception(Exception::FetchPageFault)
        | Trap::Exception(Exception::PageNonExecutableFault) => {
            handle_page_fault(tf, PageFaultFlags::EXECUTE, from_user);
        }
        Trap::Exception(Exception::PagePrivilegeIllegal) => {
            handle_page_fault(tf, PageFaultFlags::READ, from_user)
        }
        #[cfg(feature = "uspace")]
        Trap::Exception(
            Exception::FetchInstructionAddressError
            | Exception::MemoryAccessAddressError
            | Exception::AddressNotAligned,
        ) if from_user => {
            if !handle_user_signal(tf, 11) {
                panic!(
                    "Unhandled user trap {:?} @ {:#x}:\n{:#x?}",
                    estat.cause(),
                    tf.era,
                    tf
                );
            }
        }
        #[cfg(feature = "uspace")]
        Trap::Exception(
            Exception::InstructionNotExist
            | Exception::InstructionPrivilegeIllegal
            | Exception::FloatingPointUnavailable,
        ) if from_user => {
            if !handle_user_signal(tf, 4) {
                panic!(
                    "Unhandled user trap {:?} @ {:#x}:\n{:#x?}",
                    estat.cause(),
                    tf.era,
                    tf
                );
            }
        }
        Trap::Exception(Exception::Breakpoint) => handle_breakpoint(&mut tf.era),
        Trap::Interrupt(_) => {
            let irq_num: usize = estat.is().trailing_zeros() as usize;
            handle_trap!(IRQ, irq_num);
        }
        #[cfg(feature = "uspace")]
        _ if from_user => {
            if !handle_user_signal(tf, 4) {
                panic!(
                    "Unhandled user trap {:?} @ {:#x}:\n{:#x?}",
                    estat.cause(),
                    tf.era,
                    tf
                );
            }
        }
        _ => {
            panic!(
                "Unhandled trap {:?} @ {:#x}:\n{:#x?}",
                estat.cause(),
                tf.era,
                tf
            );
        }
    }

    #[cfg(feature = "uspace")]
    if from_user {
        crate::trap::handle_user_return(tf);
    }
}

